**Spring Boot Event Sourcing:**

```java
// Aggregate: rebuilt from events
public class PaymentAggregate {
    private String paymentId;
    private PaymentStatus status;
    private BigDecimal amount;
    private List<DomainEvent> changes = new ArrayList<>();

    // Rebuild from event history:
    public static PaymentAggregate reconstruct(List<DomainEvent> events) {
        PaymentAggregate agg = new PaymentAggregate();
        events.forEach(agg::apply);
        return agg;
    }

    // Apply commands: validate + create new event:
    public void initiatePayment(BigDecimal amount, String merchantId) {
        if (amount.compareTo(BigDecimal.ZERO) <= 0)
            throw new IllegalArgumentException('Amount must be positive');
        apply(new PaymentInitiatedEvent(UUID.randomUUID().toString(), amount, merchantId));
    }

    // Apply event to self (state transition):
    private void apply(PaymentInitiatedEvent e) {
        this.paymentId = e.paymentId();
        this.amount = e.amount();
        this.status = PaymentStatus.INITIATED;
        this.changes.add(e); // track new events to save
    }
}

// Event store: append-only (never update/delete):
public void save(PaymentAggregate agg) {
    agg.getChanges().forEach(event -> eventStore.append(event));
}
```

